// Input: article topic and keyword from webhook or manual trigger
const topic = $input.first()?.json?.topic || 'PC Power Management for Enterprise IT';
const keyword = $input.first()?.json?.keyword || 'pc power management software';
const customCta = $input.first()?.json?.customCta || '';

return [{
  json: {
    topic,
    keyword,
    customCta,
    userMessage: `Write a complete, publication-ready HTML article on the topic: "${topic}".\nTarget keyword: ${keyword}\nDate: 2026-04-17\nBrand: powerplug.ai\nFollow ALL rules in the system prompt exactly. Output raw HTML only, no markdown fences.${customCta ? '\nCustom CTA text: ' + customCta : ''}`,
    attempt: 1
  }
}];

// ================================================================
// VALIDATION NODE: PowerPlug Article Quality Gate
// Version: 3.0 | Date: 2026-04-17
// Checks all 34 acceptance criteria before passing to output
// ================================================================

const html = $input.first()?.json?.choices?.[0]?.message?.content || $input.first()?.json?.html || '';
const results = {};
let passed = 0;
let failed = 0;

// --- Helper: strip HTML tags to get visible text ---
function stripHtml(h) {
  return h.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
           .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
           .replace(/<[^>]+>/g, ' ')
           .replace(/&[a-z]+;/gi, ' ')
           .replace(/\s+/g, ' ').trim();
}

function check(key, condition, desc) {
  const ok = !!condition;
  results[key] = { pass: ok, desc };
  if (ok) passed++; else failed++;
  return ok;
}

// --- 1. H1 count = 1 ---
const h1Matches = (html.match(/<h1[\s>]/gi) || []).length;
check('h1_count', h1Matches === 1, `H1 count must be 1, got ${h1Matches}`);

// --- 2. No date tokens in first 600 chars of body (visible text, attrs exempt) ---
const bodyStart = html.indexOf('pp-article-');
const bodySlice = bodyStart >= 0 ? html.slice(bodyStart, bodyStart + 600) : html.slice(0, 600);
// Strip HTML attrs to get text-only content
const bodyTextSlice = bodySlice.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');
const dateMatches = bodyTextSlice.match(/20\d{2}|today|this year|last month|yesterday|currently|right now/i);
check('date_free_intro', !dateMatches, `Visible date tokens in intro: ${JSON.stringify(dateMatches)}`);

// --- 3. TOC position (after first <p>, before second <h2>) ---
const tocPos = html.indexOf('pp-toc');
const firstP = html.indexOf('<p');
const firstH2 = html.indexOf('<h2');
const secondH2 = html.indexOf('<h2', firstH2 + 4);
check('toc_after_first_p', tocPos > firstP && firstP >= 0, 'TOC must appear after first <p>');
check('toc_before_second_h2', tocPos < secondH2 && secondH2 >= 0, 'TOC must appear before second <h2>');

// --- 4. TOC no numbered labels ---
const tocSection = html.slice(html.indexOf('pp-toc-list'), html.indexOf('pp-toc-list') + 3000);
const numberedToc = tocSection.match(/<a[^>]*>\s*\d+[\.\)]/);
check('toc_no_numbers', !numberedToc, `Numbered TOC items found: ${JSON.stringify(numberedToc)}`);

// --- 5. TOC collapsed by default (aria-expanded=false) ---
check('toc_collapsed_default', html.includes('aria-expanded="false"'), 'TOC must have aria-expanded=false on load');

// --- 6. FAQ all collapsed ---
const faqTriggerCount = (html.match(/pp-faq-trigger/g) || []).length;
const faqAriaFalse = (html.match(/aria-expanded="false"/g) || []).length;
check('faq_collapsed_default', faqAriaFalse >= 1, `FAQ triggers must have aria-expanded=false, found ${faqAriaFalse}`);

// --- 7. Mid-article CTA count >= 2 ---
const ctaMidCount = (html.match(/pp-cta-mid/g) || []).length;
check('cta_mid_count', ctaMidCount >= 4, `pp-cta-mid occurrences: ${ctaMidCount} (need >= 4 for 2 blocks)`);

// --- 8. End CTA count = 1 ---
const ctaEndCount = (html.match(/pp-cta-end/g) || []).length;
check('cta_end_count', ctaEndCount >= 2, `pp-cta-end occurrences: ${ctaEndCount} (need >= 2 for 1 block)`);

// --- 9. Inline conversion links >= 2 ---
const contactLinks = (html.match(/href="https:\/\/powerplug\.ai\/contact-us"/g) || []).length;
check('inline_cta_count', contactLinks >= 2, `Contact-us href count: ${contactLinks} (need >= 2)`);

// --- 10. Tip block present ---
check('tip_present', html.includes('pp-tip'), 'Tip block (pp-tip) must be present');

// --- 11. How-To block present ---
check('howto_present', html.includes('pp-howto'), 'How-To block (pp-howto) must be present');

// --- 12. DYK block present ---
check('dyk_present', html.includes('pp-dyk'), 'Did You Know block (pp-dyk) must be present');

// --- 13. Internal links >= 3 ---
const internalLinks = (html.match(/href="https:\/\/powerplug\.ai\//g) || []).length;
check('internal_links', internalLinks >= 3, `Internal powerplug.ai links: ${internalLinks} (need >= 3)`);

// --- 14. External links with target=_blank >= 3 ---
const externalLinks = (html.match(/target="_blank"/g) || []).length;
check('external_links', externalLinks >= 3, `target=_blank links: ${externalLinks} (need >= 3)`);

// --- 15. Image integrity (no placeholder.com or data:) ---
const badImages = html.match(/src="(placeholder\.com|data:)/);
check('image_integrity', !badImages, `Bad image src found: ${JSON.stringify(badImages)}`);

// --- 16. Image count >= 4 ---
const imgCount = (html.match(/<img/gi) || []).length;
check('image_count', imgCount >= 4, `Image count: ${imgCount} (need >= 4)`);

// --- 17. Word count >= 1500 ---
const visibleText = stripHtml(html);
const wordCount = visibleText.split(/\s+/).filter(w => w.length > 0).length;
check('word_count', wordCount >= 1500, `Word count: ${wordCount} (need >= 1500)`);

// --- 18. H2 count >= 5 ---
const h2Count = (html.match(/<h2[\s>]/gi) || []).length;
check('h2_count', h2Count >= 5, `H2 count: ${h2Count} (need >= 5)`);

// --- 19. No html/head/body wrappers ---
check('no_doc_wrappers', !/<html|<head>|<body/i.test(html), 'No html/head/body tags allowed');

// --- 20. CSS scoped class present ---
check('css_scoped', /\.pp-article-/.test(html), 'CSS must be scoped under .pp-article-YYYY-MM-DD');

// --- 21. Floating contact button present ---
check('float_contact', html.includes('pp-float-contact'), 'Floating contact button (pp-float-contact) must be present');

// --- 22. Floating scroll-top present ---
check('float_top', html.includes('pp-float-top'), 'Floating scroll-top button (pp-float-top) must be present');

// --- 23. Author section with real social links ---
check('author_linkedin', html.includes('linkedin.com/company/powerplug-ltd'), 'LinkedIn verified URL must be in author section');
check('author_twitter', html.includes('twitter.com/PowerPlugLtd'), 'Twitter verified URL must be in author section');
check('author_facebook', html.includes('facebook.com/PowerPlugLtd'), 'Facebook verified URL must be in author section');

// --- 24. Real logo linked to homepage ---
check('logo_linked', html.includes('href="https://powerplug.ai/"') && html.includes('powerplug-logo.png'), 'Real logo linked to homepage required');

// --- 25. No old teal color ---
check('no_legacy_teal', !html.includes('#0fb5b0'), 'Legacy teal color #0fb5b0 must not appear');

// --- 26. RTL block present ---
check('rtl_block', html.includes('[dir="rtl"]'), 'RTL [dir=rtl] CSS block must be present');

// --- 27. Schema LocalBusiness present ---
check('schema_localbusiness', html.includes('LocalBusiness'), 'Schema.org LocalBusiness markup required');

// --- 28. Schema FAQPage present ---
check('schema_faqpage', html.includes('FAQPage'), 'Schema.org FAQPage markup required');

// --- 29. Contact URL correct (not /contact/) ---
const wrongContactUrl = html.match(/href="https:\/\/powerplug\.ai\/contact[^-]/);
check('contact_url_correct', !wrongContactUrl, 'Contact URL must be /contact-us not /contact/');

// --- 30. External links have rel=noopener ---
const noopenerCount = (html.match(/rel="noopener noreferrer"/g) || []).length;
check('external_noopener', noopenerCount >= 3, `rel=noopener noreferrer count: ${noopenerCount} (need >= 3)`);

// Summary
const allPassed = failed === 0;

return [{
  json: {
    html,
    validation_results: results,
    summary: { passed, failed, total: passed + failed },
    allPassed,
    word_count: wordCount,
    h1_count: h1Matches,
    h2_count: h2Count,
    image_count: imgCount,
    timestamp: new Date().toISOString()
  }
}];

// Build a correction prompt listing only the failed validation rules
const data = $input.first().json;
const html = data.html;
const results = data.validation_results;
const attempt = $('Prepare Prompt').first().json.attempt || 1;

if (attempt >= 3) {
  return [{ json: { ...data, flaggedForReview: true, message: 'Max retries reached. Flagged for human review.' } }];
}

const failedRules = Object.entries(results)
  .filter(([k, v]) => !v.pass)
  .map(([k, v]) => `- ${k}: ${v.desc}`)
  .join('\n');

const correctionPrompt = `The following validation rules FAILED in your previous HTML output.
Fix ONLY these issues without breaking any passing rules:

${failedRules}

Return the complete corrected HTML article. Follow all rules from the system prompt.
Attempt: ${attempt + 1} of 3`;

return [{
  json: {
    userMessage: correctionPrompt,
    previousHtml: html,
    attempt: attempt + 1,
    failedRules,
    validation_results: results
  }
}];

// Save valid HTML to file and prepare final output
const data = $input.first().json;
const html = data.html;
const timestamp = data.timestamp || new Date().toISOString();

// Build the output result object
const result = {
  status: 'success',
  message: `Article validated and ready. Passed ${data.summary.passed}/${data.summary.total} checks.`,
  validation_results: data.validation_results,
  summary: data.summary,
  word_count: data.word_count,
  h1_count: data.h1_count,
  h2_count: data.h2_count,
  image_count: data.image_count,
  file_path: 'Improved_HTML_Template.html',
  timestamp,
  html
};

return [{ json: result }];
